from pydantic_ai import Agent, Result
from pydantic import BaseModel, field_validator
from typing import Any

class CustomerProfile(BaseModel):
    customer_id: str
    email: str
    orders: list[str]

    @field_validator('email')
    @classmethod
    def check_domain_consistency(cls, v: str, values: dict[str, Any]) -> str:
        if values.get('customer_id') and '@example.com' not in v:
            raise ValueError('Customer email must use example.com domain')
        return v

    @field_validator('orders')
    @classmethod
    def validate_order_count(cls, v: list[str], values: dict[str, Any]) -> list[str]:
        expected_orders = int(values.get('customer_id', '0')) % 10 + 1
        if len(v) != expected_orders:
            raise ValueError(f'Order count {len(v)} doesn't match customer_id pattern')
        return v

agent = Agent('customer-service', result_model=CustomerProfile)
result = agent.run('Get profile for customer 12345')

import httpx
from pydantic_ai import Tool

@Tool()
def verify_customer_exists(customer_id: str) -> bool:
    '''Verify customer exists in CRM before processing'''
    async with httpx.AsyncClient() as client:
        resp = await client.get(f'https://crm.example.com/customers/{customer_id}')
        return resp.status_code == 200

class VerifiedCustomer(BaseModel):
    customer_id: str
    verified: bool = Field(default=False)

    @model_validator(mode='after')
    def verify_existence(self) -> 'VerifiedCustomer':        
        if not verify_customer_exists(self.customer_id):
            raise ValueError(f'Customer {self.customer_id} does not exist')
        self.verified = True
        return self

agent = Agent('verified-customer-lookup', result_model=VerifiedCustomer)

