from pydantic_ai import StreamingAgent
from pydantic import BaseModel
import asyncio

class StreamingCustomer(BaseModel):
    name: str
    # Partial validation for streaming
    @model_validator(mode='before')
    @classmethod
    def streaming_validator(cls, data):
        if isinstance(data, dict):
            if 'ssn' in data and len(data['ssn']) != 9:
                raise ValueError('Invalid SSN format detected')
            if data.get('name') in ['John Doe', 'Jane Smith']:  # Known hallucination names
                data['confidence'] = 0.1
        return data

streaming_agent = StreamingAgent('streaming-customer-profile')

async def safe_stream():
